import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Observable } from 'rxjs';
import { Task } from '../models/task.model';

@Injectable({ providedIn: 'root' })
export class TaskService {
  private http = inject(HttpClient);
  private apiUrl = 'http://localhost:5000/api/tasks';
  private usersUrl = 'http://localhost:5000/api/users'; 

  // --- TAREAS ---
  getTasks(): Observable<Task[]> { return this.http.get<Task[]>(this.apiUrl); }
  createTask(task: Task, idempotencyKey: string): Observable<Task> {
    const headers = new HttpHeaders({ 'Idempotency-Key': idempotencyKey });
    return this.http.post<Task>(this.apiUrl, task, { headers });
  }
  updateTask(id: string, task: Partial<Task>): Observable<Task> { return this.http.put<Task>(`${this.apiUrl}/${id}`, task); }
  deleteTask(id: string): Observable<any> { return this.http.delete(`${this.apiUrl}/${id}`); }

  // --- USUARIOS ---
  getUsers(): Observable<any[]> { return this.http.get<any[]>(this.usersUrl); }

  deleteUser(id: string): Observable<any> {
    const token = localStorage.getItem('token');
    const headers = new HttpHeaders({ 'Authorization': `Bearer ${token}` });
    return this.http.delete(`${this.usersUrl}/${id}`, { headers });
  }

  updateUserRole(id: string, role: string): Observable<any> {
    const token = localStorage.getItem('token');
    const headers = new HttpHeaders({ 'Authorization': `Bearer ${token}` });
    return this.http.put(`${this.usersUrl}/${id}/role`, { role }, { headers });
  }
}
